class MinStack:
    def __init__(self):
        self.stack = []
        self.mins = []

    def push(self, val):
        self.stack.append(val)
        self.mins.append(val if not self.mins else min(val, self.mins[-1]))

    def pop(self):
        self.stack.pop()
        self.mins.pop()

    def top(self):
        return self.stack[-1]

    def getMin(self):
        return self.mins[-1]

class Solution:
    def minStack(self, operations, values):
        obj = None
        out = []
        for op, args in zip(operations, values):
            if op == 'MinStack':
                obj = MinStack()
            elif op == 'push':
                obj.push(args[0])
            elif op == 'pop':
                obj.pop()
            elif op == 'top':
                out.append(obj.top())
            elif op == 'getMin':
                out.append(obj.getMin())
        return out
